/**
 * Hugging Face Data Loader for SAGE Benchmark Leaderboard
 *
 * Primary source:
 *   - benchmark_results.json (generated by sage-benchmark upload pipeline)
 * Legacy fallback:
 *   - leaderboard_single.json / leaderboard_multi.json (local docs data)
 */

const HF_CONFIG = {
    repo: 'intellistream/sage-benchmark-results',
    branch: 'main',
    files: {
        benchmark: 'benchmark_results.json',
        single: 'leaderboard_single.json',
        multi: 'leaderboard_multi.json',
    },
    fallbackToLocal: true,
    localPath: 'data/'
};

function normalizeWorkloadName(name) {
    if (!name) return 'Unknown';
    const raw = String(name).trim();
    const qMatch = raw.match(/^q([1-8])([_\-].*)?$/i);
    if (qMatch) return `Q${qMatch[1]}`;
    if (raw.toLowerCase().includes('scheduler')) return 'Scheduler';
    return raw;
}

function toPercent(val) {
    if (val === null || val === undefined || Number.isNaN(Number(val))) return null;
    const n = Number(val);
    return n <= 1 ? n * 100 : n;
}

function toResource(entry) {
    const nodes = Number(entry.nodes || 1);
    const parallelism = Number(entry.parallelism || 1);
    const backend = String(entry.backend || 'sage').toUpperCase();
    return {
        name: `${nodes} node${nodes > 1 ? 's' : ''} • ${backend}`,
        details: `parallelism=${parallelism}, seed=${entry.seed ?? '-'}${entry.run_id ? `, run_id=${entry.run_id}` : ''}`,
    };
}

function normalizeBenchmarkEntries(records) {
    const rows = (Array.isArray(records) ? records : []).map((entry, idx) => {
        const nodes = Number(entry.nodes || 1);
        const timestamp = entry.timestamp ? String(entry.timestamp).slice(0, 10) : '-';
        const workloadName = normalizeWorkloadName(entry.workload);
        const throughput = entry.throughput ?? null;
        const latencyP99 = entry.latency_p99 ?? entry.latency_p95 ?? entry.latency_p50 ?? null;
        const successRate = toPercent(entry.success_rate);

        return {
            entry_id: entry.run_id || `${entry.backend || 'sage'}-${workloadName}-${idx}`,
            sage_version: entry.metadata?.sage_version || entry.metadata?.benchmark_version || 'main-dev',
            timestamp,
            backend: String(entry.backend || 'sage'),
            nodes,
            parallelism: Number(entry.parallelism || 1),
            seed: entry.seed ?? null,
            config_type: nodes > 1 ? 'multi-node' : 'single-chip',
            hardware: {
                chip_model: entry.metadata?.hardware || `${nodes} node ${String(entry.backend || 'sage').toUpperCase()}`,
                chip_count: Number(entry.parallelism || 1),
            },
            model: {
                name: entry.metadata?.model_name || String(entry.backend || 'sage').toUpperCase(),
                precision: entry.metadata?.precision || 'N/A',
            },
            cluster: {
                node_count: nodes,
            },
            resource_config: toResource(entry),
            workload: {
                name: workloadName,
                type: entry.metadata?.experiment_name || String(entry.workload || 'benchmark'),
                description: entry.metadata?.scheduler_name
                    ? `scheduler=${entry.metadata.scheduler_name}`
                    : `backend=${entry.backend || 'sage'}`,
            },
            metrics: {
                throughput_qps: throughput,
                latency_p99: latencyP99,
                success_rate: successRate,
                memory_mb: null,
                accuracy_score: null,
            },
            raw_record: entry,
        };
    });

    return {
        single: rows.filter((row) => row.config_type === 'single-chip'),
        multi: rows.filter((row) => row.config_type === 'multi-node'),
    };
}

async function loadFromHuggingFace(filename) {
    const url = `https://huggingface.co/datasets/${HF_CONFIG.repo}/resolve/${HF_CONFIG.branch}/${filename}`;
    const response = await fetch(url, { headers: { Accept: 'application/json' }, cache: 'no-cache' });
    if (!response.ok) throw new Error(`HF API error: ${response.status} ${response.statusText}`);
    return await response.json();
}

async function loadFromLocal(filename) {
    const url = `${HF_CONFIG.localPath}${filename}`;
    const response = await fetch(url);
    if (!response.ok) throw new Error(`Local file error: ${response.status}`);
    return await response.json();
}

async function loadLeaderboardData() {
    const result = { single: [], multi: [] };

    try {
        const benchmarkData = await loadFromHuggingFace(HF_CONFIG.files.benchmark);
        const normalized = normalizeBenchmarkEntries(benchmarkData);
        result.single = normalized.single;
        result.multi = normalized.multi;
        console.log(`[HF Loader] ✅ Loaded benchmark_results.json: ${result.single.length} single, ${result.multi.length} multi-node`);
        return result;
    } catch (hfBenchmarkError) {
        console.warn('[HF Loader] ⚠️ benchmark_results.json unavailable:', hfBenchmarkError.message);
    }

    try {
        const [singleData, multiData] = await Promise.all([
            loadFromHuggingFace(HF_CONFIG.files.single),
            loadFromHuggingFace(HF_CONFIG.files.multi),
        ]);
        result.single = Array.isArray(singleData) ? singleData : [];
        result.multi = Array.isArray(multiData) ? multiData : [];
        console.log(`[HF Loader] ✅ Loaded legacy HF files: ${result.single.length} single, ${result.multi.length} multi`);
        return result;
    } catch (hfLegacyError) {
        console.warn('[HF Loader] ⚠️ Legacy HF files unavailable:', hfLegacyError.message);
    }

    if (HF_CONFIG.fallbackToLocal) {
        const [singleData, multiData] = await Promise.all([
            loadFromLocal(HF_CONFIG.files.single),
            loadFromLocal(HF_CONFIG.files.multi),
        ]);
        result.single = Array.isArray(singleData) ? singleData : [];
        result.multi = Array.isArray(multiData) ? multiData : [];
        console.log(`[HF Loader] ✅ Loaded local fallback: ${result.single.length} single, ${result.multi.length} multi`);
        return result;
    }

    throw new Error('Failed to load data from HF benchmark/legacy and local fallback');
}

async function getLastUpdated() {
    try {
        const data = await loadFromHuggingFace(HF_CONFIG.files.benchmark);
        if (Array.isArray(data) && data.length > 0) {
            const timestamps = data
                .map((entry) => Date.parse(entry.timestamp || ''))
                .filter((ts) => !Number.isNaN(ts));
            if (timestamps.length > 0) {
                return new Date(Math.max(...timestamps)).toISOString();
            }
        }
    } catch (_error) {
        // fallback below
    }

    try {
        const url = `https://huggingface.co/api/datasets/${HF_CONFIG.repo}`;
        const response = await fetch(url);
        if (response.ok) {
            const info = await response.json();
            return info.lastModified || null;
        }
    } catch (_error) {
        // ignore
    }
    return null;
}

window.HFDataLoader = {
    loadLeaderboardData,
    getLastUpdated,
    config: HF_CONFIG,
};
